"use strict";(globalThis.webpackChunkmy_website=globalThis.webpackChunkmy_website||[]).push([[1752],{4951(e,o,t){t.r(o),t.d(o,{assets:()=>h,contentTitle:()=>a,default:()=>d,frontMatter:()=>s,metadata:()=>n,toc:()=>l});const n=JSON.parse('{"id":"stoicism/epictetus/enchiridion/enchiridion","title":"Enchiridion","description":"Sonnet 4.6 Summary","source":"@site/docs/stoicism/epictetus/enchiridion/enchiridion.md","sourceDirName":"stoicism/epictetus/enchiridion","slug":"/stoicism/epictetus/enchiridion/","permalink":"/justinus/docs/stoicism/epictetus/enchiridion/","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":1,"frontMatter":{"title":"Enchiridion","sidebar_position":1},"sidebar":"philosophersSidebar","previous":{"title":"Book 4, Ch. 13","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-4/discourses-book-4-chapter-13"},"next":{"title":"Seneca","permalink":"/justinus/docs/stoicism/seneca/"}}');var i=t(4848),r=t(8453);const s={title:"Enchiridion",sidebar_position:1},a="Enchiridion",h={},l=[{value:"Sonnet 4.6 Summary",id:"sonnet-46-summary",level:2},{value:"Text",id:"text",level:2},{value:"<strong>One</strong> \u2014 Dichotomy of Control",id:"one--dichotomy-of-control",level:3},{value:"<strong>Two</strong> \u2014 Will to Avoid",id:"two--will-to-avoid",level:3},{value:"<strong>Three</strong> \u2014 Naming Attachments",id:"three--naming-attachments",level:3},{value:"<strong>Four</strong> \u2014 Prepare for Friction",id:"four--prepare-for-friction",level:3},{value:"<strong>Five</strong> \u2014 Judgements Disturb, Not Events",id:"five--judgements-disturb-not-events",level:3},{value:"<strong>Six</strong> \u2014 Pride in What Is Yours",id:"six--pride-in-what-is-yours",level:3},{value:"<strong>Seven</strong> \u2014 The Ship and Shore",id:"seven--the-ship-and-shore",level:3},{value:"<strong>Eight</strong> \u2014 Wish Events as They Are",id:"eight--wish-events-as-they-are",level:3},{value:"<strong>Nine</strong> \u2014 Sickness and the Will",id:"nine--sickness-and-the-will",level:3},{value:"<strong>Ten</strong> \u2014 The Right Faculty",id:"ten--the-right-faculty",level:3},{value:"<strong>Eleven</strong> \u2014 I Gave It Back",id:"eleven--i-gave-it-back",level:3},{value:"<strong>Twelve</strong> \u2014 Freedom Over Plenty",id:"twelve--freedom-over-plenty",level:3},{value:"<strong>Thirteen</strong> \u2014 Appear Foolish, Keep Progress",id:"thirteen--appear-foolish-keep-progress",level:3},{value:"<strong>Fourteen</strong> \u2014 Wanting the Impossible",id:"fourteen--wanting-the-impossible",level:3},{value:"<strong>Fifteen</strong> \u2014 The Banquet of Life",id:"fifteen--the-banquet-of-life",level:3},{value:"<strong>Sixteen</strong> \u2014 Sympathy Without Inner Grief",id:"sixteen--sympathy-without-inner-grief",level:3},{value:"<strong>Seventeen</strong> \u2014 Play the Part Given",id:"seventeen--play-the-part-given",level:3},{value:"<strong>Eighteen</strong> \u2014 Omens Mean Nothing to You",id:"eighteen--omens-mean-nothing-to-you",level:3},{value:"<strong>Nineteen</strong> \u2014 Invincibility",id:"nineteen--invincibility",level:3},{value:"<strong>Twenty</strong> \u2014 Anger Is Your Own Thought",id:"twenty--anger-is-your-own-thought",level:3},{value:"<strong>Twenty-One</strong> \u2014 Keep Death Before You",id:"twenty-one--keep-death-before-you",level:3},{value:"<strong>Twenty-Two</strong> \u2014 Endure Ridicule for Philosophy",id:"twenty-two--endure-ridicule-for-philosophy",level:3},{value:"<strong>Twenty-Three</strong> \u2014 Do Not Seek to Please",id:"twenty-three--do-not-seek-to-please",level:3},{value:"<strong>Twenty-Four</strong> \u2014 Honour Is Not in Others&#39; Hands",id:"twenty-four--honour-is-not-in-others-hands",level:3},{value:"<strong>Twenty-Five</strong> \u2014 The Price of Favour",id:"twenty-five--the-price-of-favour",level:3},{value:"<strong>Twenty-Six</strong> \u2014 Apply Rules to Yourself",id:"twenty-six--apply-rules-to-yourself",level:3},{value:"<strong>Twenty-Seven</strong> \u2014 Nothing Intrinsically Evil",id:"twenty-seven--nothing-intrinsically-evil",level:3},{value:"<strong>Twenty-Eight</strong> \u2014 Do Not Trust Your Mind to Strangers",id:"twenty-eight--do-not-trust-your-mind-to-strangers",level:3},{value:"<strong>Twenty-Nine</strong> \u2014 Count the Cost First",id:"twenty-nine--count-the-cost-first",level:3},{value:"<strong>Thirty</strong> \u2014 Duties Follow Relations",id:"thirty--duties-follow-relations",level:3},{value:"<strong>Thirty-One</strong> \u2014 Piety Toward the Gods",id:"thirty-one--piety-toward-the-gods",level:3},{value:"<strong>Thirty-Two</strong> \u2014 On Consulting Oracles",id:"thirty-two--on-consulting-oracles",level:3},{value:"<strong>Thirty-Three</strong> \u2014 Rules of Conduct",id:"thirty-three--rules-of-conduct",level:3},{value:"<strong>Thirty-Four</strong> \u2014 Pause Before Pleasure",id:"thirty-four--pause-before-pleasure",level:3},{value:"<strong>Thirty-Five</strong> \u2014 Act Without Fear of Judgement",id:"thirty-five--act-without-fear-of-judgement",level:3},{value:"<strong>Thirty-Six</strong> \u2014 Things Combined Lose Meaning",id:"thirty-six--things-combined-lose-meaning",level:3},{value:"<strong>Thirty-Seven</strong> \u2014 Do Not Overreach Your Part",id:"thirty-seven--do-not-overreach-your-part",level:3},{value:"<strong>Thirty-Eight</strong> \u2014 Guard the Governing Principle",id:"thirty-eight--guard-the-governing-principle",level:3},{value:"<strong>Thirty-Nine</strong> \u2014 Property Has a Measure",id:"thirty-nine--property-has-a-measure",level:3},{value:"<strong>Forty</strong> \u2014 Women and True Honour",id:"forty--women-and-true-honour",level:3},{value:"<strong>Forty-One</strong> \u2014 The Body Is Secondary",id:"forty-one--the-body-is-secondary",level:3},{value:"<strong>Forty-Two</strong> \u2014 He Thought It Right",id:"forty-two--he-thought-it-right",level:3},{value:"<strong>Forty-Three</strong> \u2014 Two Handles",id:"forty-three--two-handles",level:3},{value:"<strong>Forty-Four</strong> \u2014 Illogical Superiority",id:"forty-four--illogical-superiority",level:3},{value:"<strong>Forty-Five</strong> \u2014 Describe, Do Not Judge",id:"forty-five--describe-do-not-judge",level:3},{value:"<strong>Forty-Six</strong> \u2014 Act the Principles, Do Not Proclaim Them",id:"forty-six--act-the-principles-do-not-proclaim-them",level:3},{value:"<strong>Forty-Seven</strong> \u2014 Simple Life Without Display",id:"forty-seven--simple-life-without-display",level:3},{value:"<strong>Forty-Eight</strong> \u2014 The Philosopher Looks Inward",id:"forty-eight--the-philosopher-looks-inward",level:3},{value:"<strong>Forty-Nine</strong> \u2014 Understanding Is Not Enough",id:"forty-nine--understanding-is-not-enough",level:3},{value:"<strong>Fifty</strong> \u2014 Hold to Principles as Laws",id:"fifty--hold-to-principles-as-laws",level:3},{value:"<strong>Fifty-One</strong> \u2014 Three Departments of Philosophy",id:"fifty-one--three-departments-of-philosophy",level:3},{value:"<strong>Fifty-Two</strong> \u2014 Follow Willingly",id:"fifty-two--follow-willingly",level:3}];function u(e){const o={em:"em",h1:"h1",h2:"h2",h3:"h3",header:"header",p:"p",strong:"strong",...(0,r.R)(),...e.components},{Details:t}=o;return t||function(e,o){throw new Error("Expected "+(o?"component":"object")+" `"+e+"` to be defined: you likely forgot to import, pass, or provide it.")}("Details",!0),(0,i.jsxs)(i.Fragment,{children:[(0,i.jsx)("div",{style:{textAlign:"center"},children:(0,i.jsx)(o.header,{children:(0,i.jsx)(o.h1,{id:"enchiridion",children:"Enchiridion"})})}),"\n",(0,i.jsxs)(t,{open:!0,children:[(0,i.jsx)("summary",{children:"Sonnet 4.6 Summary"}),(0,i.jsx)(o.h2,{id:"sonnet-46-summary",children:"Sonnet 4.6 Summary"}),(0,i.jsxs)(o.p,{children:[(0,i.jsx)(o.strong,{children:"Core Premise (Ch. 1)"}),"\nEverything divides into two categories: what is ",(0,i.jsx)(o.em,{children:"in our power"})," (thoughts, desires, judgments) and what is ",(0,i.jsx)(o.em,{children:"not in our power"})," (body, reputation, wealth, others' actions). Freedom and happiness come from focusing exclusively on the former and releasing attachment to the latter."]}),(0,i.jsx)(o.p,{children:(0,i.jsx)(o.strong,{children:"Key Themes:"})}),(0,i.jsxs)(o.p,{children:[(0,i.jsx)(o.strong,{children:"Control and acceptance"})," \u2014 You cannot control events, only your response to them. Don't wish things were different; wish your will to align with how things are. Sickness hinders the body, not the will. Lameness hinders the leg, not the will."]}),(0,i.jsxs)(o.p,{children:[(0,i.jsx)(o.strong,{children:"Desire and aversion"})," \u2014 Avoid directing desire toward external things, since failure to get them makes you miserable. Direct aversion only toward what is within your control and contrary to nature."]}),(0,i.jsxs)(o.p,{children:[(0,i.jsx)(o.strong,{children:"Impressions and judgment"}),' \u2014 When a disturbing thought arises, confront it: "You are just an impression." What upsets people isn\'t events themselves, but their ',(0,i.jsx)(o.em,{children:"judgments"})," about events \u2014 as Epictetus puts it, death wasn't dreadful to Socrates."]}),(0,i.jsxs)(o.p,{children:[(0,i.jsx)(o.strong,{children:"Detachment without coldness"}),' \u2014 Love your family, enjoy pleasures, but hold them lightly. When you lose something, say "I gave it back," not "I lost it." When you kiss your child, remind yourself you are kissing a mortal \u2014 this isn\'t morbid, it\'s preparation.']}),(0,i.jsxs)(o.p,{children:[(0,i.jsx)(o.strong,{children:"Social conduct"})," \u2014 Don't gossip, compare yourself to others, or seek praise. Be gentle with those who wrong you; they act from their own (mistaken) judgment. Don't call yourself a philosopher \u2014 live the principles instead. \"Sheep don't show their shepherd the grass they've eaten; they produce wool and milk.\""]}),(0,i.jsxs)(o.p,{children:[(0,i.jsx)(o.strong,{children:"Progress in philosophy"})," \u2014 A person making true progress blames no one, praises no one, complains of nothing, and guards against himself as his own worst enemy. The goal of philosophy is ",(0,i.jsx)(o.em,{children:"action"})," in accordance with principles, not clever analysis of texts."]}),(0,i.jsxs)(o.p,{children:[(0,i.jsx)(o.strong,{children:"Urgency"})," \u2014 Don't wait. You are grown. Begin now. Every action either maintains or loses the progress you've made."]}),(0,i.jsxs)(o.p,{children:["It's a remarkably compact manual \u2014 52 short chapters \u2014 and the whole thing amounts to one consistent message: ",(0,i.jsx)(o.em,{children:"the only thing that can harm you is your own judgment, and that is the one thing entirely yours to command."})]})]}),"\n",(0,i.jsxs)(t,{open:!0,children:[(0,i.jsx)("summary",{children:"Text"}),(0,i.jsx)(o.h2,{id:"text",children:"Text"}),(0,i.jsxs)(o.h3,{id:"one--dichotomy-of-control",children:[(0,i.jsx)(o.strong,{children:"One"})," \u2014 Dichotomy of Control"]}),(0,i.jsx)(o.p,{children:"Of all existing things some are in our power, and others are not in our\npower. In our power are thought, impulse, will to get and will to avoid,\nand, in a word, everything which is our own doing. Things not in our\npower include the body, property, reputation, office, and, in a word,\neverything which is not our own doing. Things in our power are by\nnature free, unhindered, untrammelled; things not in our power are\nweak, servile, subject to hindrance, dependent on others. Remember\nthen that if you imagine that what is naturally slavish is free, and what\nis naturally another\u2019s is your own, you will be hampered, you will\nmourn, you will be put to confusion, you will blame gods and men;\nbut if you think that only your own belongs to you, and that what\nis another\u2019s is indeed another\u2019s, no one will ever put compulsion or\nhindrance on you, you will blame none, you will accuse none, you\nwill do nothing against your will, no one will harm you, you will have\nno enemy, for no harm can touch you.\nAiming then at these high matters, you must remember that to attain\nthem requires more than ordinary effort; you will have to give up\nsome things entirely, and put off others for the moment. And if you\nwould have these also\u2014office and wealth\u2014it may be that you will fail\nto get them, just because your desire is set on the former, and you will\ncertainly fail to attain those things which alone bring freedom and\nhappiness.\nMake it your study then to confront every harsh impression with the\nwords, \u201cYou are but an impression, and not at all what you seem to\nbe\u201d. Then test it by those rules that you possess; and first by this\u2014the\nchief test of all\u2014\u201cIs it concerned with what is in our power or with\nwhat is not in our power?\u201d And if it is concerned with what is not in\nour power, be ready with the answer that it is nothing to you."}),(0,i.jsxs)(o.h3,{id:"two--will-to-avoid",children:[(0,i.jsx)(o.strong,{children:"Two"})," \u2014 Will to Avoid"]}),(0,i.jsx)(o.p,{children:"Remember that the will to get promises attainment of what you will,\nand the will to avoid promises escape from what you avoid; and he\nwho fails to get what he wills is unfortunate, and he who does not\nescape what he wills to avoid is miserable. If then you try to avoid\nonly what is unnatural in the region within your control, you will\nescape from all that you avoid; but if you try to avoid disease or death\nor poverty you will be miserable.\nTherefore let your will to avoid have no concern with what is not in\nman\u2019s power; direct it only to things in man\u2019s power that are contrary\nto nature. But for the moment you must utterly remove the will to\nget; for if you will to get something not in man\u2019s power you are bound\nto be unfortunate; while none of the things in man\u2019s power that you\ncould honourably will to get is yet within your reach. Impulse to act\nand not to act, these are your concern; yet exercise them gently and\nwithout strain, and provisionally."}),(0,i.jsxs)(o.h3,{id:"three--naming-attachments",children:[(0,i.jsx)(o.strong,{children:"Three"})," \u2014 Naming Attachments"]}),(0,i.jsx)(o.p,{children:"When anything, from the meanest thing upwards, is attractive or serviceable or an object of affection, remember always to say to yourself,\n\u201cWhat is its nature?\u201d If you are fond of a jug, say you are fond of a jug;\nthen you will not be disturbed if it be broken. If you kiss your child or\nyour wife, say to yourself that you are kissing a human being, for then\nif death strikes it you will not be disturbed."}),(0,i.jsxs)(o.h3,{id:"four--prepare-for-friction",children:[(0,i.jsx)(o.strong,{children:"Four"})," \u2014 Prepare for Friction"]}),(0,i.jsx)(o.p,{children:"When you are about to take something in hand, remind yourself what\nmanner of thing it is. If you are going to bathe put before your mind\nwhat happens in the bath\u2014water pouring over some, others being\njostled, some reviling, others stealing; and you will set to work more\nsecurely if you say to yourself at once: \u201cI want to bathe, and I want to\nkeep my will in harmony with nature,\u201d and so in each thing you do;\nfor in this way, if anything turns up to hinder you in your bathing, you\nwill be ready to say, \u201cI did not want only to bathe, but to keep my will\nin harmony with nature, and I shall not so keep it, if I lose my temper\nat what happens.\u201d"}),(0,i.jsxs)(o.h3,{id:"five--judgements-disturb-not-events",children:[(0,i.jsx)(o.strong,{children:"Five"})," \u2014 Judgements Disturb, Not Events"]}),(0,i.jsx)(o.p,{children:"What disturbs men\u2019s minds is not events but their judgements on\nevents: For instance, death is nothing dreadful, or else Socrates would\nhave thought it so. No, the only dreadful thing about it is men\u2019s judgement that it is dreadful. And so when we are hindered, or disturbed,\nor distressed, let us never lay the blame on others, but on ourselves,\nthat is, on our own judgements. To accuse others for one\u2019s own misfortunes is a sign of want of education; to accuse oneself shows that one\u2019s\neducation has begun; to accuse neither oneself nor others shows that\none\u2019s education is complete."}),(0,i.jsxs)(o.h3,{id:"six--pride-in-what-is-yours",children:[(0,i.jsx)(o.strong,{children:"Six"})," \u2014 Pride in What Is Yours"]}),(0,i.jsx)(o.p,{children:"Be not elated at an excellence which is not your own. If the horse in\nhis pride were to say, \u201cI am handsome,\u201d we could bear with it. But\nwhen you say with pride, \u201cI have a handsome horse,\u201d know that the\ngood horse is the ground of your pride. You ask then what you can call\nyour own. The answer is\u2014the way you deal with your impressions.\nTherefore when you deal with your impressions in accord with nature,\nthen you may be proud indeed, for your pride will be in a good which\nis your own."}),(0,i.jsxs)(o.h3,{id:"seven--the-ship-and-shore",children:[(0,i.jsx)(o.strong,{children:"Seven"})," \u2014 The Ship and Shore"]}),(0,i.jsx)(o.p,{children:"When you are on a voyage, and your ship is at anchorage, and you\ndisembark to get fresh water, you may pick up a small shellfish or a\ntruffle by the way, but you must keep your attention fixed on the ship,\nand keep looking towards it constantly, to see if the Helmsman calls\nyou; and if he does, you have to leave everything, or be bundled on\nboard with your legs tied like a sheep. So it is in life. If you have a dear\nwife or child given you, they are like the shellfish or the truffle, they\nare very well in their way. Only, if the Helmsman call, run back to your\nship, leave all else, and do not look behind you. And if you are old,\nnever go far from the ship, so that when you are called you may not\nfail to appear."}),(0,i.jsxs)(o.h3,{id:"eight--wish-events-as-they-are",children:[(0,i.jsx)(o.strong,{children:"Eight"})," \u2014 Wish Events as They Are"]}),(0,i.jsx)(o.p,{children:"Ask not that events should happen as you will, but let your will be\nthat events should happen as they do, and you shall have peace."}),(0,i.jsxs)(o.h3,{id:"nine--sickness-and-the-will",children:[(0,i.jsx)(o.strong,{children:"Nine"})," \u2014 Sickness and the Will"]}),(0,i.jsx)(o.p,{children:"Sickness is a hindrance to the body, but not to the will, unless the\nwill consent. Lameness is a hindrance to the leg, but not to the will.\nSay this to yourself at each event that happens, for you shall find that\nthough it hinders something else it will not hinder you."}),(0,i.jsxs)(o.h3,{id:"ten--the-right-faculty",children:[(0,i.jsx)(o.strong,{children:"Ten"})," \u2014 The Right Faculty"]}),(0,i.jsx)(o.p,{children:"When anything happens to you, always remember to turn to yourself\nand ask what faculty you have to deal with it. If you see a beautiful\nboy or a beautiful woman, you will find continence the faculty to\nexercise there; if trouble is laid on you, you will find endurance; if\nribaldry, you will find patience. And if you train yourself in this habit\nyour impressions will not carry you away."}),(0,i.jsxs)(o.h3,{id:"eleven--i-gave-it-back",children:[(0,i.jsx)(o.strong,{children:"Eleven"})," \u2014 I Gave It Back"]}),(0,i.jsx)(o.p,{children:"Never say of anything, \u201cI lost it,\u201d but say, \u201cI gave it back.\u201d Has your\nchild died? It was given back. Has your wife died? She was given back.\nHas your estate been taken from you? Was not this also given back?\nBut you say, \u201cHe who took it from me is wicked.\u201d What does it matter\nto you through whom the Giver asked it back? As long as He gives it\nyou, take care of it, but not as your own; treat it as passers-by treat an\ninn."}),(0,i.jsxs)(o.h3,{id:"twelve--freedom-over-plenty",children:[(0,i.jsx)(o.strong,{children:"Twelve"})," \u2014 Freedom Over Plenty"]}),(0,i.jsx)(o.p,{children:"If you wish to make progress, abandon reasonings of this sort: \u201cIf I\nneglect my affairs I shall have nothing to live on;\u201d \u201cIf I do not punish\nmy son, he will be wicked.\u201d For it is better to die of hunger, so that\nyou be free from pain and free from fear, than to live in plenty and\nbe troubled in mind. It is better for your son to be wicked than for\nyou to be miserable. Wherefore begin with little things. Is your drop\nof oil spilt? Is your sup of wine stolen? Say to yourself, \u201cThis is the\nprice paid for freedom from passion, this is the price of a quiet mind.\u201d\nNothing can be had without a price. When you call your slave-boy,\nreflect that he may not be able to hear you, and if he hears you, he\nmay not be able to do anything you want. But he is not so well off that\nit rests with him to give you peace of mind."}),(0,i.jsxs)(o.h3,{id:"thirteen--appear-foolish-keep-progress",children:[(0,i.jsx)(o.strong,{children:"Thirteen"})," \u2014 Appear Foolish, Keep Progress"]}),(0,i.jsx)(o.p,{children:"If you wish to make progress, you must be content in external matters to seem a fool and a simpleton; do not wish men to think you\nknow anything, and if any should think you to be somebody, distrust\nyourself. For know that it is not easy to keep your will in accord with\nnature and at the same time keep outward things; if you attend to one\nyou must needs neglect the other."}),(0,i.jsxs)(o.h3,{id:"fourteen--wanting-the-impossible",children:[(0,i.jsx)(o.strong,{children:"Fourteen"})," \u2014 Wanting the Impossible"]}),(0,i.jsx)(o.p,{children:"It is silly to want your children and your wife and your friends to live\nfor ever, for that means that you want what is not in your control to\nbe in your control, and what is not your own to be yours. In the same\nway if you want your servant to make no mistakes, you are a fool, for\nyou want vice not to be vice but something different. But if you want\nnot to be disappointed in your will to get, you can attain to that.\nExercise yourself then in what lies in your power. Each man\u2019s master\nis the man who has authority over what he wishes or does not wish,\nto secure the one or to take away the other. Let him then who wishes\nto be free not wish for anything or avoid anything that depends on\nothers; or else he is bound to be a slave."}),(0,i.jsxs)(o.h3,{id:"fifteen--the-banquet-of-life",children:[(0,i.jsx)(o.strong,{children:"Fifteen"})," \u2014 The Banquet of Life"]}),(0,i.jsx)(o.p,{children:"Remember that you must behave in life as you would at a banquet. A\ndish is handed round and comes to you; put out your hand and take\nit politely. It passes you; do not stop it. It has not reached you; do not\nbe impatient to get it, but wait till your turn comes. Bear yourself thus\ntowards children, wife, office, wealth, and one day you will be worthy\nto banquet with the gods. But if when they are set before you, you do\nnot take them but despise them, then you shall not only share the\ngods\u2019 banquet, but shall share their rule. For by so doing Diogenes\nand Heraclitus and men like them were called divine and deserved\nthe name."}),(0,i.jsxs)(o.h3,{id:"sixteen--sympathy-without-inner-grief",children:[(0,i.jsx)(o.strong,{children:"Sixteen"})," \u2014 Sympathy Without Inner Grief"]}),(0,i.jsx)(o.p,{children:"When you see a man shedding tears in sorrow for a child abroad or\ndead, or for loss of property, beware that you are not carried away by\nthe impression that it is outward ills that make him miserable. Keep\nthis thought by you: \u201cWhat distresses him is not the event, for that\ndoes not distress another, but his judgement on the event.\u201d Therefore\ndo not hesitate to sympathize with him so far as words go, and if it so\nchance, even to groan with him; but take heed that you do not also\ngroan in your inner being."}),(0,i.jsxs)(o.h3,{id:"seventeen--play-the-part-given",children:[(0,i.jsx)(o.strong,{children:"Seventeen"})," \u2014 Play the Part Given"]}),(0,i.jsx)(o.p,{children:"Remember that you are an actor in a play, and the Playwright chooses\nthe manner of it: if he wants it short, it is short; if long, it is long. If\nhe wants you to act a poor man you must act the part with all your\npowers; and so if your part be a cripple or a magistrate or a plain man.\nFor your business is to act the character that is given you and act it\nwell; the choice of the cast is Another\u2019s."}),(0,i.jsxs)(o.h3,{id:"eighteen--omens-mean-nothing-to-you",children:[(0,i.jsx)(o.strong,{children:"Eighteen"})," \u2014 Omens Mean Nothing to You"]}),(0,i.jsx)(o.p,{children:"When a raven croaks with evil omen, let not the impression carry you\naway, but straightway distinguish in your own mind and say, \u201cThese\nportents mean nothing to me; but only to my bit of a body or my\nbit of property or name, or my children or my wife. But for me all\nomens are favourable if I will, for, whatever the issue may be, it is in\nmy power to benefit therefrom.\u201d"}),(0,i.jsxs)(o.h3,{id:"nineteen--invincibility",children:[(0,i.jsx)(o.strong,{children:"Nineteen"})," \u2014 Invincibility"]}),(0,i.jsx)(o.p,{children:"You can be invincible, if you never enter on a contest where victory\nis not in your power. Beware then that when you see a man raised to\nhonour or great power or high repute you do not let your impression\ncarry you away. For if the reality of good lies in what is in our power,\nthere is no room for envy or jealousy. And you will not wish to be\npraetor, or prefect or consul, but to be free; and there is but one way\nto freedom\u2014to despise what is not in our power."}),(0,i.jsxs)(o.h3,{id:"twenty--anger-is-your-own-thought",children:[(0,i.jsx)(o.strong,{children:"Twenty"})," \u2014 Anger Is Your Own Thought"]}),(0,i.jsx)(o.p,{children:"Remember that foul words or blows in themselves are no outrage, but\nyour judgement that they are so. So when any one makes you angry,\nknow that it is your own thought that has angered you. Wherefore\nmake it your first endeavour not to let your impressions carry you\naway. For if once you gain time and delay, you will find it easier to\ncontrol yourself."}),(0,i.jsxs)(o.h3,{id:"twenty-one--keep-death-before-you",children:[(0,i.jsx)(o.strong,{children:"Twenty-One"})," \u2014 Keep Death Before You"]}),(0,i.jsx)(o.p,{children:"Keep before your eyes from day to day death and exile and all things\nthat seem terrible, but death most of all, and then you will never set\nyour thoughts on what is low and will never desire anything beyond\nmeasure."}),(0,i.jsxs)(o.h3,{id:"twenty-two--endure-ridicule-for-philosophy",children:[(0,i.jsx)(o.strong,{children:"Twenty-Two"})," \u2014 Endure Ridicule for Philosophy"]}),(0,i.jsx)(o.p,{children:"If you set your desire on philosophy you must at once prepare to meet\nwith ridicule and the jeers of many who will say, \u201cHere he is again,\nturned philosopher. Where has he got these proud looks?\u201d Nay, put on\nno proud looks, but hold fast to what seems best to you, in confidence\nthat God has set you at this post. And remember that if you abide\nwhere you are, those who first laugh at you will one day admire you,\nand that if you give way to them, you will get doubly laughed at."}),(0,i.jsxs)(o.h3,{id:"twenty-three--do-not-seek-to-please",children:[(0,i.jsx)(o.strong,{children:"Twenty-Three"})," \u2014 Do Not Seek to Please"]}),(0,i.jsx)(o.p,{children:"If it ever happen to you to be diverted to things outside, so that you\ndesire to please another, know that you have lost your life\u2019s plan. Be\ncontent then always to be a philosopher; if you wish to be regarded\nas one too, show yourself that you are one and you will be able to\nachieve it."}),(0,i.jsxs)(o.h3,{id:"twenty-four--honour-is-not-in-others-hands",children:[(0,i.jsx)(o.strong,{children:"Twenty-Four"})," \u2014 Honour Is Not in Others' Hands"]}),(0,i.jsx)(o.p,{children:"Let not reflections such as these afflict you: \u201cI shall live without honour, and never be of any account\u201d; for if lack of honour is an evil, no\none but yourself can involve you in evil any more than in shame. Is it\nyour business to get office or to be invited to an entertainment?\nCertainly not.\nWhere then is the dishonour you talk of? How can you be \u201cof no\naccount anywhere,\u201d when you ought to count for something in those\nmatters only which are in your power, where you may achieve the\nhighest worth? \u201cBut my friends,\u201d you say, \u201cwill lack assistance.\u201d\nWhat do you mean by \u201clack assistance?\u201d They will not have cash from\nyou and you will not make them Roman citizens. Who told you that\nto do these things is in our power, and not dependent upon others?\nWho can give to another what is not his to give?\n\u201cGet them then,\u201d says he, \u201cthat we may have them.\u201d\nIf I can get them and keep my self-respect, honour, magnanimity,\nshow the way and I will get them. But if you call on me to lose the\ngood things that are mine, in order that you may win things that are\nnot good, look how unfair and thoughtless you are. And which do\nyou really prefer? Money, or a faithful, modest friend? Therefore help\nme rather to keep these qualities, and do not expect from me actions\nwhich will make me lose them.\n\u201cBut my country,\u201d says he, \u201cwill lack assistance, so far as lies in me.\u201d\nOnce more I ask, what assistance do you mean? It will not owe colonnades or baths to you. What of that? It does not owe shoes to the\nblacksmith or arms to the shoemaker; it is sufficient if each man fulfils his own function. Would you do it no good if you secured to it\nanother faithful and modest citizen?\n\u201cYes.\u201d\nWell, then, you would not be useless to it.\n\u201cWhat place then shall I have in the city?\u201d\nWhatever place you can hold while you keep your character for honour and self-respect. But if you are going to lose these qualities in\ntrying to benefit your city, what benefit, I ask, would you have done\nher when you attain to the perfection of being lost to shame and\nhonour?"}),(0,i.jsxs)(o.h3,{id:"twenty-five--the-price-of-favour",children:[(0,i.jsx)(o.strong,{children:"Twenty-Five"})," \u2014 The Price of Favour"]}),(0,i.jsx)(o.p,{children:"Has some one had precedence of you at an entertainment or a levee\nor been called in before you to give advice? If these things are good\nyou ought to be glad that he got them; if they are evil, do not be angry\nthat you did not get them yourself. Remember that if you want to get\nwhat is not in your power, you cannot earn the same reward as others\nunless you act as they do. How is it possible for one who does not\nhaunt the great man\u2019s door to have equal shares with one who does,\nor one who does not go in his train equality with one who does; or\none who does not praise him with one who does? You will be unjust\nthen and insatiable if you wish to get these privileges for nothing,\nwithout paying their price. What is the price of a lettuce? An obol\nperhaps. If then a man pays his obol and gets his lettuces, and you do\nnot pay and do not get them, do not think you are defrauded. For as\nhe has the lettuces so you have the obol you did not give. The same\nprinciple holds good too in conduct. You were not invited to some\none\u2019s entertainment? Because you did not give the host the price for\nwhich he sells his dinner. He sells it for compliments, he sells it for\nattentions. Pay him the price then, if it is to your profit. But if you\nwish to get the one and yet not give up the other, nothing can satisfy\nyou in your folly.\nWhat! you say, you have nothing instead of the dinner?\nNay, you have this, you have not praised the man you did not want to\npraise, you have not had to bear with the insults of his doorstep."}),(0,i.jsxs)(o.h3,{id:"twenty-six--apply-rules-to-yourself",children:[(0,i.jsx)(o.strong,{children:"Twenty-Six"})," \u2014 Apply Rules to Yourself"]}),(0,i.jsx)(o.p,{children:"It is in our power to discover the will of Nature from those matters on\nwhich we have no difference of opinion. For instance, when another\nman\u2019s slave has broken the wine-cup we are very ready to say at\nonce, \u201cSuch things must happen.\u201d Know then that when your own\ncup is broken, you ought to behave in the same way as when your\nneighbour\u2019s was broken. Apply the same principle to higher matters.\nIs another\u2019s child or wife dead? Not one of us but would say, \u201cSuch\nis the lot of man;\u201d but when one\u2019s own dies, straightway one cries,\n\u201cAlas! miserable am I.\u201d But we ought to remember what our feelings\nare when we hear it of another."}),(0,i.jsxs)(o.h3,{id:"twenty-seven--nothing-intrinsically-evil",children:[(0,i.jsx)(o.strong,{children:"Twenty-Seven"})," \u2014 Nothing Intrinsically Evil"]}),(0,i.jsx)(o.p,{children:"As a mark is not set up for men to miss it, so there is nothing intrinsically evil in the world."}),(0,i.jsxs)(o.h3,{id:"twenty-eight--do-not-trust-your-mind-to-strangers",children:[(0,i.jsx)(o.strong,{children:"Twenty-Eight"})," \u2014 Do Not Trust Your Mind to Strangers"]}),(0,i.jsx)(o.p,{children:"If any one trusted your body to the first man he met, you would be\nindignant, but yet you trust your mind to the chance corner, and\nallow it to be disturbed and confounded if he revile you; are you not\nashamed to do so?"}),(0,i.jsxs)(o.h3,{id:"twenty-nine--count-the-cost-first",children:[(0,i.jsx)(o.strong,{children:"Twenty-Nine"})," \u2014 Count the Cost First"]}),(0,i.jsx)(o.p,{children:"In everything you do consider what comes first and what follows, and\nso approach it. Otherwise you will come to it with a good heart at first\nbecause you have not reflected on any of the consequences, and afterwards, when difficulties have appeared, you will desist to your shame.\nDo you wish to win at Olympia? So do I, by the gods, for it is a fine\nthing. But consider the first steps to it, and the consequences, and so\nlay your hand to the work. You must submit to discipline, eat to order,\ntouch no sweets, train under compulsion, at a fixed hour, in heat and\ncold, drink no cold water, nor wine, except by order; you must hand\nyourself over completely to your trainer as you would to a physician,\nand then when the contest comes you must risk getting hacked, and\nsometimes dislocate your hand, twist your ankle, swallow plenty of\nsand, sometimes get a flogging, and with all this suffer defeat. When\nyou have considered all this well, then enter on the athlete\u2019s course,\nif you still wish it. If you act without thought you will be behaving"}),(0,i.jsx)(o.p,{children:"like children, who one day play at wrestlers, another day at gladiators,\nnow sound the trumpet, and next strut the stage. Like them you will\nbe now an athlete, now a gladiator, then orator, then philosopher,\nbut nothing with all your soul. Like an ape, you imitate every sight\nyou see, and one thing after another takes your fancy. When you\nundertake a thing you do it casually and halfheartedly, instead of considering it and looking at it all round. In the same way some people,\nwhen they see a philosopher and hear a man speaking like Euphrates\n(and indeed who can speak as he can? ), wish to be philosophers\nthemselves. Man, consider first what it is you are undertaking; then\nlook at your own powers and see if you can bear it. Do you want to\ncompete in the pentathlon or in wrestling? Look to your arms, your\nthighs, see what your loins are like. For different men are born for\ndifferent tasks. Do you suppose that if you do this you can live as you\ndo now\u2014eat and drink as you do now, indulge desire and discontent\njust as before? Nay, you must sit up late, work hard, abandon your\nown people, be looked down on by a mere slave, be ridiculed by those\nwho meet you, get the worst of it in everything\u2014in honour, in office,\nin justice, in every possible thing. This is what you have to consider:\nwhether you are willing to pay this price for peace of mind, freedom,\ntranquillity. If not, do not come near; do not be, like the children,\nfirst a philosopher, then a tax-collector, then an orator, then one of\nCaesar\u2019s procurators. These callings do not agree. You must be one\nman, good or bad; you must develop either your Governing Principle,\nor your outward endowments; you must study either your inner man,\nor outward things\u2014in a word, you must choose between the position\nof a philosopher and that of a mere outsider."}),(0,i.jsxs)(o.h3,{id:"thirty--duties-follow-relations",children:[(0,i.jsx)(o.strong,{children:"Thirty"})," \u2014 Duties Follow Relations"]}),(0,i.jsx)(o.p,{children:"Appropriate acts are in general measured by the relations they are\nconcerned with. \u201cHe is your father.\u201d This means you are called on to\ntake care of him, give way to him in all things, bear with him if he\nreviles or strikes you.\n\u201cBut he is a bad father.\u201d\nWell, have you any natural claim to a good father? No, only to a father.\n\u201cMy brother wrongs me.\u201d\nBe careful then to maintain the relation you hold to him, and do not\nconsider what he does, but what you must do if your purpose is to\nkeep in accord with nature. For no one shall harm you, without your\nconsent; you will only be harmed, when you think you are harmed.\nYou will only discover what is proper to expect from neighbour, citizen, or praetor, if you get into the habit of looking at the relations\nimplied by each."}),(0,i.jsxs)(o.h3,{id:"thirty-one--piety-toward-the-gods",children:[(0,i.jsx)(o.strong,{children:"Thirty-One"})," \u2014 Piety Toward the Gods"]}),(0,i.jsx)(o.p,{children:"For piety towards the gods know that the most important thing is\nthis: to have right opinions about them\u2014that they exist, and that they\ngovern the universe well and justly\u2014and to have set yourself to obey\nthem, and to give way to all that happens, following events with a\nfree will, in the belief that they are fulfilled by the highest mind. For\nthus you will never blame the gods, nor accuse them of neglecting\nyou. But this you cannot achieve, unless you apply your conception\nof good and evil to those things only which are in our power, and not\nto those which are out of our power. For if you apply your notion of\ngood or evil to the latter, then, as soon as you fail to get what you will\nto get or fail to avoid what you will to avoid, you will be bound to\nblame and hate those you hold responsible. For every living creature\nhas a natural tendency to avoid and shun what seems harmful and\nall that causes it, and to pursue and admire what is helpful and all\nthat causes it. It is not possible then for one who thinks he is harmed\nto take pleasure in what he thinks is the author of the harm, any\nmore than to take pleasure in the harm itself. That is why a father is\nreviled by his son, when he does not give his son a share of what the\nson regards as good things; thus Polynices and Eteocles were set at\nenmity with one another by thinking that a king\u2019s throne was a good\nthing. That is why the farmer, and the sailor, and the merchant, and\nthose who lose wife or children revile the gods. For men\u2019s religion is\nbound up with their interest. Therefore he who makes it his concern\nrightly to direct his will to get and his will to avoid, is thereby making\npiety his concern. But it is proper on each occasion to make libation\nand sacrifice and to offer first-fruits according to the custom of our\nfathers, with purity and not in slovenly or careless fashion, without\nmeanness and without extravagance."}),(0,i.jsxs)(o.h3,{id:"thirty-two--on-consulting-oracles",children:[(0,i.jsx)(o.strong,{children:"Thirty-Two"})," \u2014 On Consulting Oracles"]}),(0,i.jsx)(o.p,{children:"When you make use of prophecy remember that while you know not\nwhat the issue will be, but are come to learn it from the prophet, you\ndo know before you come what manner of thing it is, if you are really\na philosopher. For if the event is not in our control, it cannot be either\ngood or evil. Therefore do not bring with you to the prophet the will\nto get or the will to avoid, and do not approach him with trembling,\nbut with your mind made up, that the whole issue is indifferent and\ndoes not affect you and that, whatever it be, it will be in your power\nto make good use of it, and no one shall hinder this. With confidence\nthen approach the gods as counsellors, and further, when the counsel\nis given you, remember whose counsel it is, and whom you will be disregarding if you disobey. And consult the oracle, as Socrates thought\nmen should, only when the whole question turns upon the issue of\nevents, and neither reason nor any art of man provides opportunities\nfor discovering what lies before you. Therefore, when it is your duty to\nrisk your life with friend or country, do not ask the oracle whether you\nshould risk your life. For if the prophet warns you that the sacrifice\nis unfavourable, though it is plain that this means death or exile or\ninjury to some part of your body, yet reason requires that even at this\ncost you must stand by your friend and share your country\u2019s danger.\nWherefore pay heed to the greater prophet, Pythian Apollo, who cast\nout of his temple the man who did not help his friend when he was\nbeing killed."}),(0,i.jsxs)(o.h3,{id:"thirty-three--rules-of-conduct",children:[(0,i.jsx)(o.strong,{children:"Thirty-Three"})," \u2014 Rules of Conduct"]}),(0,i.jsx)(o.p,{children:"Lay down for yourself from the first a definite stamp and style of\nconduct, which you will maintain when you are alone and also in\nthe society of men. Be silent for the most part, or, if you speak, say\nonly what is necessary and in a few words. Talk, but rarely, if occasion calls you, but do not talk of ordinary things\u2014of gladiators, or\nhorse-races, or athletes, or of meats or drinks\u2014these are topics that\narise everywhere\u2014but above all do not talk about men in blame or\ncompliment or comparison. If you can, turn the conversation of your\ncompany by your talk to some fitting subject; but if you should chance\nto be isolated among strangers, be silent. Do not laugh much, nor at\nmany things, nor without restraint.\nRefuse to take oaths, altogether if that be possible, but if not, as far as\ncircumstances allow.\nRefuse the entertainments of strangers and the vulgar. But if occasion\narise to accept them, then strain every nerve to avoid lapsing into\nthe state of the vulgar. For know that, if your comrade have a stain\non him, he that associates with him must needs share the stain, even\nthough he be clean in himself.\nFor your body take just so much as your bare need requires, such as\nfood, drink, clothing, house, servants, but cut down all that tends to\nluxury and outward show.\nAvoid impurity to the utmost of your power before marriage, and\nif you indulge your passion, let it be done lawfully. But do not be\noffensive or censorious to those who indulge it, and do not be always\nbringing up your own chastity. If some one tells you that so and so\nspeaks ill of you, do not defend yourself against what he says, but\nanswer, \u201cHe did not know my other faults, or he would not have\nmentioned these alone.\u201d\nIt is not necessary for the most part to go to the games; but if you\nshould have occasion to go, show that your first concern is for yourself; that is, wish that only to happen which does happen, and him\nonly to win who does win, for so you will suffer no hindrance. But\nrefrain entirely from applause, or ridicule, or prolonged excitement.\nAnd when you go away do not talk much of what happened there,\nexcept so far as it tends to your improvement. For to talk about it\nimplies that the spectacle excited your wonder."}),(0,i.jsx)(o.p,{children:"Do not go lightly or casually to hear lectures; but if you do go, maintain\nyour gravity and dignity and do not make yourself offensive. When\nyou are going to meet any one, and particularly some man of reputed\neminence, set before your mind the thought, \u201cWhat would Socrates\nor Zeno have done?\u201d and you will not fail to make proper use of the\noccasion. When you go to visit some great man, prepare your mind\nby thinking that you will not find him in, that you will be shut out,\nthat the doors will be slammed in your face, that he will pay no heed\nto you. And if in spite of all this you find it fitting for you to go, go\nand bear what happens and never say to yourself, \u201cIt was not worth\nall this;\u201d for that shows a vulgar mind and one at odds with outward\nthings.\nIn your conversation avoid frequent and disproportionate mention\nof your own doings or adventures; for other people do not take the\nsame pleasure in hearing what has happened to you as you take in\nrecounting your adventures.\nAvoid raising men\u2019s laughter; for it is a habit that easily slips into\nvulgarity, and it may well suffice to lessen your neighbour\u2019s respect.\nIt is dangerous too to lapse into foul language; when anything of the\nkind occurs, rebuke the offender, if the occasion allow, and if not,\nmake it plain to him by your silence, or a blush or a frown, that you\nare angry at his words."}),(0,i.jsxs)(o.h3,{id:"thirty-four--pause-before-pleasure",children:[(0,i.jsx)(o.strong,{children:"Thirty-Four"})," \u2014 Pause Before Pleasure"]}),(0,i.jsx)(o.p,{children:"When you imagine some pleasure, beware that it does not carry you\naway, like other imaginations. Wait a while, and give yourself pause.\nNext remember two things: how long you will enjoy the pleasure, and"}),(0,i.jsx)(o.p,{children:"also how long you will afterwards repent and revile yourself. And\nset on the other side the joy and self-satisfaction you will feel if you\nrefrain. And if the moment seems come to realize it, take heed that\nyou be not overcome by the winning sweetness and attraction of it; set\nin the other scale the thought how much better is the consciousness\nof having vanquished it."}),(0,i.jsxs)(o.h3,{id:"thirty-five--act-without-fear-of-judgement",children:[(0,i.jsx)(o.strong,{children:"Thirty-Five"})," \u2014 Act Without Fear of Judgement"]}),(0,i.jsx)(o.p,{children:"When you do a thing because you have determined that it ought to\nbe done, never avoid being seen doing it, even if the opinion of the\nmultitude is going to condemn you. For if your action is wrong, then\navoid doing it altogether, but if it is right, why do you fear those who\nwill rebuke you wrongly?"}),(0,i.jsxs)(o.h3,{id:"thirty-six--things-combined-lose-meaning",children:[(0,i.jsx)(o.strong,{children:"Thirty-Six"})," \u2014 Things Combined Lose Meaning"]}),(0,i.jsx)(o.p,{children:"The phrases, \u201cIt is day\u201d and \u201cIt is night,\u201d mean a great deal if taken\nseparately, but have no meaning if combined. In the same way, to\nchoose the larger portion at a banquet may be worth while for your\nbody, but if you want to maintain social decencies it is worthless.\nTherefore, when you are at meat with another, remember not only to\nconsider the value of what is set before you for the body, but also to\nmaintain your self-respect before your host."}),(0,i.jsxs)(o.h3,{id:"thirty-seven--do-not-overreach-your-part",children:[(0,i.jsx)(o.strong,{children:"Thirty-Seven"})," \u2014 Do Not Overreach Your Part"]}),(0,i.jsx)(o.p,{children:"If you try to act a part beyond your powers, you not only disgrace\nyourself in it, but you neglect the part which you could have filled\nwith success."}),(0,i.jsxs)(o.h3,{id:"thirty-eight--guard-the-governing-principle",children:[(0,i.jsx)(o.strong,{children:"Thirty-Eight"})," \u2014 Guard the Governing Principle"]}),(0,i.jsx)(o.p,{children:"As in walking you take care not to tread on a nail or to twist your foot,\nso take care that you do not harm your Governing Principle. And if\nwe guard this in everything we do, we shall set to work more securely."}),(0,i.jsxs)(o.h3,{id:"thirty-nine--property-has-a-measure",children:[(0,i.jsx)(o.strong,{children:"Thirty-Nine"})," \u2014 Property Has a Measure"]}),(0,i.jsx)(o.p,{children:"Every man\u2019s body is a measure for his property, as the foot is the\nmeasure for his shoe. If you stick to this limit, you will keep the right\nmeasure; if you go beyond it, you are bound to be carried away down\na precipice in the end; just as with the shoe, if you once go beyond\nthe foot, your shoe puts on gilding, and soon purple and embroidery.\nFor when once you go beyond the measure there is no limit."}),(0,i.jsxs)(o.h3,{id:"forty--women-and-true-honour",children:[(0,i.jsx)(o.strong,{children:"Forty"})," \u2014 Women and True Honour"]}),(0,i.jsx)(o.p,{children:"Women from fourteen years upwards are called \u201cmadam\u201d by men.\nWherefore, when they see that the only advantage they have got is\nto be marriageable, they begin to make themselves smart and to\nset all their hopes on this. We must take pains then to make them\nunderstand that they are really honoured for nothing but a modest\nand decorous life."}),(0,i.jsxs)(o.h3,{id:"forty-one--the-body-is-secondary",children:[(0,i.jsx)(o.strong,{children:"Forty-One"})," \u2014 The Body Is Secondary"]}),(0,i.jsx)(o.p,{children:"It is a sign of a dull mind to dwell upon the cares of the body, to\nprolong exercise, eating, drinking, and other bodily functions. These\nthings are to be done by the way; all your attention must be given to\nthe mind."}),(0,i.jsxs)(o.h3,{id:"forty-two--he-thought-it-right",children:[(0,i.jsx)(o.strong,{children:"Forty-Two"})," \u2014 He Thought It Right"]}),(0,i.jsx)(o.p,{children:"When a man speaks evil or does evil to you, remember that he does\nor says it because he thinks it is fitting for him. It is not possible for\nhim to follow what seems good to you, but only what seems good to\nhim, so that, if his opinion is wrong, he suffers, in that he is the victim\nof deception. In the same way, if a composite judgement which is\ntrue is thought to be false, it is not the judgement that suffers, but the\nman who is deluded about it. If you act on this principle you will be\ngentle to him who reviles you, saying to yourself on each occasion,\n\u201cHe thought it right.\u201d"}),(0,i.jsxs)(o.h3,{id:"forty-three--two-handles",children:[(0,i.jsx)(o.strong,{children:"Forty-Three"})," \u2014 Two Handles"]}),(0,i.jsx)(o.p,{children:"Everything has two handles, one by which you can carry it, the other\nby which you cannot. If your brother wrongs you, do not take it by\nthat handle, the handle of his wrong, for you cannot carry it by that,\nbut rather by the other handle\u2014that he is a brother, brought up with\nyou, and then you will take it by the handle that you can carry by."}),(0,i.jsxs)(o.h3,{id:"forty-four--illogical-superiority",children:[(0,i.jsx)(o.strong,{children:"Forty-Four"})," \u2014 Illogical Superiority"]}),(0,i.jsx)(o.p,{children:"It is illogical to reason thus, \u201cI am richer than you, therefore I am superior to you,\u201d \u201cI am more eloquent than you, therefore I am superior\nto you.\u201d It is more logical to reason, \u201cI am richer than you, therefore\nmy property is superior to yours,\u201d \u201cI am more eloquent than you,\ntherefore my speech is superior to yours.\u201d You are something more\nthan property or speech."}),(0,i.jsxs)(o.h3,{id:"forty-five--describe-do-not-judge",children:[(0,i.jsx)(o.strong,{children:"Forty-Five"})," \u2014 Describe, Do Not Judge"]}),(0,i.jsx)(o.p,{children:"If a man wash quickly, do not say that he washes badly, but that\nhe washes quickly. If a man drink much wine, do not say that he\ndrinks badly, but that he drinks much. For till you have decided what\njudgement prompts him, how do you know that he acts badly? If you\ndo as I say, you will assent to your apprehensive impressions and to\nnone other."}),(0,i.jsxs)(o.h3,{id:"forty-six--act-the-principles-do-not-proclaim-them",children:[(0,i.jsx)(o.strong,{children:"Forty-Six"})," \u2014 Act the Principles, Do Not Proclaim Them"]}),(0,i.jsx)(o.p,{children:"On no occasion call yourself a philosopher, nor talk at large of your\nprinciples among the multitude, but act on your principles. For instance, at a banquet do not say how one ought to eat, but eat as\nyou ought. Remember that Socrates had so completely got rid of the\nthought of display that when men came and wanted an introduction\nto philosophers he took them to be introduced; so patient of neglect\nwas he. And if a discussion arise among the multitude on some principle, keep silent for the most part; for you are in great danger of\nblurting out some undigested thought. And when some one says to\nyou, \u201cYou know nothing,\u201d and you do not let it provoke you, then\nknow that you are really on the right road. For sheep do not bring\ngrass to their shepherds and show them how much they have eaten,\nbut they digest their fodder and then produce it in the form of wool\nand milk. Do the same yourself; instead of displaying your principles\nto the multitude, show them the results of the principles you have\ndigested."}),(0,i.jsxs)(o.h3,{id:"forty-seven--simple-life-without-display",children:[(0,i.jsx)(o.strong,{children:"Forty-Seven"})," \u2014 Simple Life Without Display"]}),(0,i.jsx)(o.p,{children:"When you have adopted the simple life, do not pride yourself upon\nit, and if you are a water-drinker do not say on every occasion, \u201cI am\na water-drinker.\u201d And if you ever want to train laboriously, keep it\nto yourself and do not make a show of it. Do not embrace statues. If\nyou are very thirsty take a good draught of cold water, and rinse you\nmouth and tell no one."}),(0,i.jsxs)(o.h3,{id:"forty-eight--the-philosopher-looks-inward",children:[(0,i.jsx)(o.strong,{children:"Forty-Eight"})," \u2014 The Philosopher Looks Inward"]}),(0,i.jsx)(o.p,{children:"The ignorant man\u2019s position and character is this: he never looks\nto himself for benefit or harm, but to the world outside him. The\nphilosopher\u2019s position and character is that he always look to himself\nfor benefit and harm.\nThe signs of one who is making progress are: he blames none, praises\nnone, complains of none, accuses none, never speaks of himself as if\nhe were somebody, or as if he knew anything. And if any one compliments him he laughs in himself at his compliment; and if one blames\nhim, he makes no defence. He goes about like a convalescent, careful\nnot to disturb his constitution on its road to recovery, until it has got\nfirm hold. He has got rid of the will to get, and his will to avoid is\ndirected no longer to what is beyond our power but only to what is in\nour power and contrary to nature. In all things he exercises his will\nwithout strain. If men regard him as foolish or ignorant he pays no\nheed. In one word, he keeps watch and guard on himself as his own\nenemy, lying in wait for him."}),(0,i.jsxs)(o.h3,{id:"forty-nine--understanding-is-not-enough",children:[(0,i.jsx)(o.strong,{children:"Forty-Nine"})," \u2014 Understanding Is Not Enough"]}),(0,i.jsx)(o.p,{children:"When a man prides himself on being able to understand and interpret the books of Chrysippus, say to yourself, \u201cIf Chrysippus had not\nwritten obscurely this man would have had nothing on which to pride\nhimself.\u201d\nWhat is my object? To understand Nature and follow her. I look then\nfor some one who interprets her, and having heard that Chrysippus\ndoes I come to him. But I do not understand his writings, so I seek an interpreter. So far there is nothing to be proud of. But when I have found\nthe interpreter it remains for me to act on his precepts; that and that\nalone is a thing to be proud of. But if I admire the mere power of exposition, it comes to this\u2014that I am turned into a grammarian instead\nof a philosopher, except that I interpret Chrysippus in place of Homer.\nTherefore, when some one says to me, \u201cRead me Chrysippus,\u201d when I\ncannot point to actions which are in harmony and correspondence\nwith his teaching, I am rather inclined to blush."}),(0,i.jsxs)(o.h3,{id:"fifty--hold-to-principles-as-laws",children:[(0,i.jsx)(o.strong,{children:"Fifty"})," \u2014 Hold to Principles as Laws"]}),(0,i.jsx)(o.p,{children:"Whatever principles you put before you, hold fast to them as laws\nwhich it will be impious to transgress. But pay no heed to what any\none says of you; for this is something beyond your own control.\nHow long will you wait to think yourself worthy of the highest and\ntransgress in nothing the clear pronouncement of reason? You have\nreceived the precepts which you ought to accept, and you have accepted them. Why then do you still wait for a master, that you may\ndelay the amendment of yourself till he comes? You are a youth no\nlonger, you are now a full-grown man. If now you are careless and\nindolent and are always putting off, fixing one day after another as\nthe limit when you mean to begin attending to yourself, then, living\nor dying, you will make no progress but will continue unawares in\nignorance. Therefore make up your mind before it is too late to live as\none who is mature and proficient, and let all that seems best to you\nbe a law that you cannot transgress. And if you encounter anything\ntroublesome or pleasant or glorious or inglorious, remember that the\nhour of struggle is come, the Olympic contest is here and you may put\noff no longer, and that one day and one action determines whether\nthe progress you have achieved is lost or maintained.\nThis was how Socrates attained perfection, paying heed to nothing\nbut reason, in all that he encountered. And if you are not yet Socrates,\nyet ought you to live as one who would wish to be a Socrates."}),(0,i.jsxs)(o.h3,{id:"fifty-one--three-departments-of-philosophy",children:[(0,i.jsx)(o.strong,{children:"Fifty-One"})," \u2014 Three Departments of Philosophy"]}),(0,i.jsx)(o.p,{children:"The first and most necessary department of philosophy deals with the\napplication of principles; for instance, \u201cnot to lie.\u201d The second deals\nwith demonstrations; for instance, \u201cHow comes it that one ought not\nto lie?\u201d The third is concerned with establishing and analysing these\nprocesses; for instance, \u201cHow comes it that this is a demonstration?\nWhat is demonstration, what is consequence, what is contradiction,\nwhat is true, what is false?\u201d It follows then that the third department\nis necessary because of the second, and the second because of the\nfirst. The first is the most necessary part, and that in which we must\nrest. But we reverse the order: we occupy ourselves with the third, and\nmake that our whole concern, and the first we completely neglect.\nWherefore we lie, but are ready enough with the demonstration that\nlying is wrong."}),(0,i.jsxs)(o.h3,{id:"fifty-two--follow-willingly",children:[(0,i.jsx)(o.strong,{children:"Fifty-Two"})," \u2014 Follow Willingly"]}),(0,i.jsx)(o.p,{children:"On every occasion we must have these thoughts at hand,\n\u201cLead me, O Zeus, and lead me, Destiny,\nWhither ordained is by your decree.\nI\u2019ll follow, doubting not, or if with will\nRecreant I falter, I shall follow still.\u201d1\n\u201cWho rightly with necessity complies In things divine we\ncount him skilled and wise.\u201d2"}),(0,i.jsx)(o.p,{children:"Cleanthes\nEuripides, Fragment 965"})]})]})}function d(e={}){const{wrapper:o}={...(0,r.R)(),...e.components};return o?(0,i.jsx)(o,{...e,children:(0,i.jsx)(u,{...e})}):u(e)}},8453(e,o,t){t.d(o,{R:()=>s,x:()=>a});var n=t(6540);const i={},r=n.createContext(i);function s(e){const o=n.useContext(r);return n.useMemo(function(){return"function"==typeof e?e(o):{...o,...e}},[o,e])}function a(e){let o;return o=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:s(e.components),n.createElement(r.Provider,{value:o},e.children)}}}]);